def gen(rng, size):
    n = max(2, min(size, 100000))
    favorite = []
    for i in range(n):
        f = rng.randint(0, n - 1)
        while f == i:
            f = rng.randint(0, n - 1)
        favorite.append(f)
    return [favorite]

