class Solution:
    def maximumInvitations(self, favorite):
        from itertools import combinations, permutations
        n = len(favorite)
        for k in range(n, 1, -1):
            found = False
            for combo in combinations(range(n), k):
                for perm in permutations(combo):
                    ok = True
                    for idx in range(k):
                        person = perm[idx]
                        left = perm[idx - 1]
                        right = perm[(idx + 1) % k]
                        if favorite[person] != left and favorite[person] != right:
                            ok = False
                            break
                    if ok:
                        found = True
                        break
                if found:
                    break
            if found:
                return k
        return 0

