class Solution:
    def maximumInvitations(self, favorite) -> int:
        from collections import deque
        n = len(favorite)
        indeg = [0] * n
        for f in favorite:
            indeg[f] += 1
        dist = [0] * n
        visited = [False] * n
        q = deque(i for i in range(n) if indeg[i] == 0)
        while q:
            u = q.popleft()
            visited[u] = True
            v = favorite[u]
            if dist[u] + 1 > dist[v]:
                dist[v] = dist[u] + 1
            indeg[v] -= 1
            if indeg[v] == 0:
                q.append(v)
        longest_cycle = 0
        two_cycle_total = 0
        for i in range(n):
            if visited[i]:
                continue
            cycle = []
            cur = i
            while not visited[cur]:
                visited[cur] = True
                cycle.append(cur)
                cur = favorite[cur]
            clen = len(cycle)
            if clen == 2:
                a, b = cycle
                two_cycle_total += 2 + dist[a] + dist[b]
            else:
                longest_cycle = max(longest_cycle, clen)
        return max(longest_cycle, two_cycle_total)

