var maximumInvitations = function(favorite) {
    const n = favorite.length;
    const indeg = new Int32Array(n);
    for (const f of favorite) indeg[f]++;
    const dist = new Int32Array(n);
    const visited = new Uint8Array(n);
    const queue = [];
    for (let i = 0; i < n; i++) if (indeg[i] === 0) queue.push(i);
    let head = 0;
    while (head < queue.length) {
        const u = queue[head++];
        visited[u] = 1;
        const v = favorite[u];
        if (dist[u] + 1 > dist[v]) dist[v] = dist[u] + 1;
        indeg[v]--;
        if (indeg[v] === 0) queue.push(v);
    }
    let longestCycle = 0;
    let twoCycleTotal = 0;
    for (let i = 0; i < n; i++) {
        if (visited[i]) continue;
        const cycle = [];
        let cur = i;
        while (!visited[cur]) {
            visited[cur] = 1;
            cycle.push(cur);
            cur = favorite[cur];
        }
        const clen = cycle.length;
        if (clen === 2) {
            const a = cycle[0], b = cycle[1];
            twoCycleTotal += 2 + dist[a] + dist[b];
        } else {
            longestCycle = Math.max(longestCycle, clen);
        }
    }
    return Math.max(longestCycle, twoCycleTotal);
};
